public JDOMAttributeIterator(NodePointer parent, QName name) {
    this.parent = parent;
    if (parent.getNode() instanceof Element) {
        Element element = (Element) parent.getNode();
        String prefix = name.getPrefix();
        Namespace ns = null;
        if (prefix != null) {
            if (prefix.equals("xml")) {
                ns = Namespace.XML_NAMESPACE;
            }
            else {
                String uri = parent.getNamespaceResolver().getNamespaceURI(prefix);
                if (uri != null) {
                    ns = Namespace.getNamespace(prefix, uri);
                }
                if (ns == null) {
                    // No attributes
                    attributes = Collections.emptyList();
                    return;
                }
            }
        }
        else {
            ns = Namespace.NO_NAMESPACE;
        }

        String lname = name.getName();
        if (!lname.equals("*")) {
            attributes = new ArrayList<>();
            if (ns != null) {
                Attribute attr = element.getAttribute(lname, ns);
                if (attr != null) {
                    attributes.add(attr);
                }
            }
        }
        else {
            attributes = new ArrayList<>();
            List<Attribute> allAttributes = element.getAttributes();
            for (Attribute attr : allAttributes) {
                if (name.getPrefix() == null || attr.getNamespace().equals(ns)) {
                    attributes.add(attr);
                }
            }
        }
    }
}
